def _resolve_dynamic_defaults(self, ctx: Context) -> None:
    """Second-pass resolution for options whose ``default`` is a
    dynamic default mapping (a ``dict`` keyed by other option
    declarations). Runs after all parameters have been parsed from
    the command line, environment variables, and the default map,
    so it can look at the final values of the options it depends on.
    """
    if ctx.resilient_parsing:
        return

    params = self.get_params(ctx)
    option_by_decl: dict[str, Option] = {}

    for param in params:
        if isinstance(param, Option):
            for decl in (*param.opts, *param.secondary_opts):
                option_by_decl[decl] = param

    for param in params:
        if not isinstance(param, Option) or not param._dynamic_default:
            continue

        if ctx.get_parameter_source(param.name) != ParameterSource.DEFAULT:  # type: ignore[arg-type]
            continue

        resolved = None

        for decl, mapping in param._dynamic_default.items():
            source = option_by_decl.get(decl)

            if source is None:
                continue

            key = str(ctx.params.get(source.name))  # type: ignore[arg-type]

            if key in mapping:
                resolved = mapping[key]

        if resolved is not None:
            ctx.params[param.name] = param.type_cast_value(ctx, resolved)  # type: ignore[index]

